static const NSUInteger kBuiltinLangsCount =
    sizeof(kBuiltinLangs) / sizeof(kBuiltinLangs[0]);

const NppBuiltinLang *NppBuiltinLanguagesAll(NSUInteger *outCount) {
    if (outCount) *outCount = kBuiltinLangsCount;
    return kBuiltinLangs;
}

// Lazily-built O(1) indices keyed by internalName.
static NSDictionary<NSString *, NSString *> *captionIndex(void) {
    static NSDictionary *idx;
    static dispatch_once_t once;
    dispatch_once(&once, ^{
        NSMutableDictionary *m = [NSMutableDictionary dictionaryWithCapacity:kBuiltinLangsCount];
        for (NSUInteger i = 0; i < kBuiltinLangsCount; i++) {
            m[@(kBuiltinLangs[i].internalName)] = @(kBuiltinLangs[i].caption);
        }
        idx = [m copy];
    });
    return idx;
}

static NSDictionary<NSString *, NSString *> *lexerIndex(void) {
    static NSDictionary *idx;
    static dispatch_once_t once;
    dispatch_once(&once, ^{
        NSMutableDictionary *m = [NSMutableDictionary dictionaryWithCapacity:kBuiltinLangsCount];
        for (NSUInteger i = 0; i < kBuiltinLangsCount; i++) {
            m[@(kBuiltinLangs[i].internalName)] = @(kBuiltinLangs[i].lexerID);
        }
        idx = [m copy];
    });
    return idx;
}

NSString *NppBuiltinLanguageCaptionForInternal(NSString *internalName) {
    return internalName.length ? captionIndex()[internalName] : nil;
}

NSString *NppBuiltinLanguageLexerIDForInternal(NSString *internalName) {
    return internalName.length ? lexerIndex()[internalName] : nil;
}
